// 链式并查集
void solve(int CASE)
{
	ll n, m; cin >> n >> m;
	var a = vector<ll>(n + 1);
	fa(i, 1, n)cin >> a[i];

	var s = vector<ll>(n + 2);
	var sum = vector<ll>(n + 2);
	var siz = vector<ll>(n + 2);
	fa(i, 1, n)s[i] = i, sum[i] = a[i], siz[i] = 1;
	s[n + 1] = n + 1;
	var find = [&](var find, int x)->int {
		if (s[x] == x)return x;
		return s[x] = find(find, s[x]);
		};

	while (m--) {
		int op; cin >> op;
		if (op == 1) {
			int l, r; cin >> l >> r;
			for (int i = find(find, l); i < r; i = find(find, i + 1)) {
				int j = find(find, i + 1);
				s[i] = j;
				sum[j] += sum[i];
				siz[j] += siz[i];
			}
		}
		else {
			int i; cin >> i;
			int e = find(find, i);
			cout << fixed << setprecision(12) << (db)sum[e] / siz[e] << endl;
		}
	}
	return;
}

// 珂朵莉树
class ODT {
private:
	struct ODT_Node {
		int l, r;
		mutable pll v; // { 总数，个数 }

		// 重载小于号以用于 set 排序
		bool operator<(const ODT_Node& a)const {
			return l < a.l;
		}
	};

	set<ODT_Node> se;

public:
	ODT(int n, const vector<ll>& a) {
		fa(i, 1, n)se.insert({ i, i, { a[i], 1 } });
	}

	// ODT 的核心操作：区间赋值（推平）
	void assign(int l, int r) {
		// 必须先 split 右边，再 split 左边，否则迭代器可能失效

		auto it = se.lower_bound({ l, 0, {0, 0} });
		auto itl = it;
		if (it != se.end() and it->l == l)itl = it;
		else {
			it = prev(it);
			itl = it;
		}

		it = se.lower_bound({ r, 0, {0, 0} });
		auto itr = it;
		if (it != se.end() and it->l == r)itr = it;
		else {
			it = prev(it);
			itr = it;
		}

		int L = itl->l, R = itr->r;
		it = itl;
		ll sum = 0, cnt = 0;
		while (it != itr) {
			auto [l, r, v] = *it;
			sum += v.px;
			cnt += v.py;
			it = se.erase(it);
		}
		sum += itr->v.px;
		cnt += itr->v.py;
		it = se.erase(it);

		se.insert({ L, R, { sum, cnt } });
	}

	pll query(int pos) {
		auto it = se.lower_bound({ pos, 0, {0, 0} });
		if (it != se.end() and it->l == pos)return it->v;
		it = prev(it);
		return it->v;
	}
};
void solve(int CASE)
{
	ll n, m; cin >> n >> m;
	var a = vector<ll>(n + 1);
	fa(i, 1, n)cin >> a[i];
	var odt = ODT(n, a);
	while (m--) {
		int op; cin >> op;
		if (op == 1) {
			int l, r; cin >> l >> r;
			odt.assign(l, r);
		}
		else {
			int i; cin >> i;
			var[sum, siz] = odt.query(i);
			cout << fixed << setprecision(12) << (db)sum / siz << endl;
		}
	}
	return;
}
